const body = $input.first().json.body;
const request_id = body.request_id || 'unknown';
const original_input = body.original_input || {};
const vision_result = body.vision_result || null;
const text_result = body.text_result || null;
const trace = body.trace || [];
const errors = [];

let visionFindings = { top_objects: [], details: [] };
if (vision_result && vision_result.detections) {
  const allObjects = [];
  for (const det of vision_result.detections) {
    for (const obj of (det.objects || [])) {
      allObjects.push(obj);
      visionFindings.details.push({ image_index: det.image_index, label: obj.label, score: obj.score, box: obj.box });
    }
  }
  const sorted = allObjects.sort((a, b) => b.score - a.score);
  visionFindings.top_objects = sorted.slice(0, 5).map(o => o.label);
} else if (!vision_result) {
  errors.push('Vision data not available');
}

let textFindings = { label: null, confidence: null, entities: [] };
if (text_result && text_result.classification) {
  textFindings.label = text_result.classification.label || null;
  textFindings.confidence = text_result.classification.confidence || null;
} else if (!text_result) {
  errors.push('Text data not available');
}

let summaryParts = [];
if (visionFindings.top_objects.length > 0) {
  summaryParts.push('Detected objects: ' + visionFindings.top_objects.join(', '));
}
if (textFindings.label) {
  summaryParts.push('Text classified as: ' + textFindings.label + ' (confidence: ' + (textFindings.confidence || 0).toFixed(2) + ')');
}
const summary = summaryParts.length > 0 ? summaryParts.join('. ') + '.' : 'No analysis results available.';

let recommendations = [];
if (textFindings.label === 'safety_hazard') recommendations.push('Immediate safety inspection recommended');
if (textFindings.label === 'equipment_failure') recommendations.push('Schedule maintenance review');
if (textFindings.label === 'maintenance_issue') recommendations.push('Log maintenance ticket');
if (textFindings.label === 'environmental_concern') recommendations.push('Environmental assessment needed');
if (visionFindings.top_objects.includes('person')) recommendations.push('Personnel detected - verify access authorization');
if (recommendations.length === 0) recommendations.push('No immediate action required');

const report = {
  request_id: request_id,
  summary: summary,
  findings: { vision: visionFindings, text: textFindings },
  recommendations: recommendations,
  trace: trace,
  errors: errors
};

return [{ json: report }];
